import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.DpI_zlPE.js";var i=JSON.parse(`{"title":"无线路由器分享","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/无线路由器/无线路由器分享.md","filePath":"ccc/无线路由器/无线路由器分享.md"}`),a={name:`ccc/无线路由器/无线路由器分享.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h1 id="无线路由器分享" tabindex="-1">无线路由器分享 <a class="header-anchor" href="#无线路由器分享" aria-label="Permalink to “无线路由器分享”">​</a></h1><p>2021.1.25</p><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to “参考链接”">​</a></h2><p><a href="http://www.acwifi.net/" target="_blank" rel="noreferrer">acwifi</a>拆了大量路由器并做了一些具有参考价值的测试</p><p><a href="https://www.right.com.cn/forum/thread-1136101-1-1.html" target="_blank" rel="noreferrer">恩山loi2404收集的大量无线路由器芯片与二级功放配置</a></p><h2 id="穿墙利器mesh" tabindex="-1">穿墙利器mesh <a class="header-anchor" href="#穿墙利器mesh" aria-label="Permalink to “穿墙利器mesh”">​</a></h2><p>  贵价路由的穿墙能力受限于物理规律与接收设备的功率，提升非常小。而mesh能显著提升覆盖范围，并且无缝漫游，无感知切换。</p><p>  mesh基于网络协议802.11s，只需要路由器支持。比较新的快速漫游由802.11k,v,r三个协议组成，需要手机支持。<a href="https://support.apple.com/zh-cn/HT202628" target="_blank" rel="noreferrer">查看苹果关于这三个协议的介绍</a>.</p><p>  组mesh更推荐wifi6路由器，普遍优化做的更好，协议支持度也更高。</p><p>  天邑TY300以及TY400降价到70左右，组mesh实在划算，不在乎二手首选。</p><p>  水星D19g够便宜，也能实现次节点200兆以及无感漫游，但是细节相对竞品略逊一筹。</p><p>  华为，小米是相对性价比高，体验也不错的方案。</p><p>  <a href="https://www.acwifi.net/9909.html" target="_blank" rel="noreferrer">由acwfi站长整理的路由器mesh协议支持情况</a></p><p>  商业化固件刷机实现mesh相对便宜，又能获得不错的体验。比如高通方案刷openwrt。其中super-wrt 深耕高通方案的wifi驱动，其无线驱动稳定性明显高于开源驱动。二手的tp 941n等高通方案路由器一般才十几块。</p><p>  手头有斐讯k2，k2p等联发科方案矿渣的，可以刷集客AP或者高恪固件。</p><h2 id="mu-mimo" tabindex="-1">mu-mimo <a class="header-anchor" href="#mu-mimo" aria-label="Permalink to “mu-mimo”">​</a></h2><p>  mu-mimo兼容性暂时很差，除非未来各厂商达成共识，或者你所有的设备都是某家公司全家桶。一旦解决了兼容性问题，mu-mimo能显著改善多用户体验，让4×4产品有用武之地。但是现在4×4产品体验上没有拉开差距。</p><h2 id="稳定-断流" tabindex="-1">稳定，断流 <a class="header-anchor" href="#稳定-断流" aria-label="Permalink to “稳定，断流”">​</a></h2><p><strong>几乎每款都有人说断流，所谓断流不可尽信</strong></p><p>  最重要的必然是稳定，但是显然稳定性很难通过测试量化。每天定时重启一般能一定程度上避免不稳定。</p><h2 id="干扰" tabindex="-1">干扰 <a class="header-anchor" href="#干扰" aria-label="Permalink to “干扰”">​</a></h2><p>  无线最大的问题是干扰，包括邻居的干扰和家里设备间干扰。解决设备间干扰可以考虑买两个路由器，一个跑在36-64信道上，另一个跑在149-161信道上，哪个信道干扰少就专门用来打游戏。2.4Ghz的干扰太多了，能用5Ghz尽量用5Ghz。</p><h2 id="_64-256-1024qam提升多大" tabindex="-1">64，256，1024QAM提升多大？ <a class="header-anchor" href="#_64-256-1024qam提升多大" aria-label="Permalink to “64，256，1024QAM提升多大？”">​</a></h2><p>  64QAM是11n标准，256QAM是wifi5（11ac）标准，wifi5只包括5g频段，部分芯片在2.4g上也支持256QAM。1024QAM是wifi6（11ax）标准，包括2.4g和5g。</p><p>  1024QAM（2^10）有10个二进制位。256QAM(2^8) 有8个二进制位，所以理论最大速率是1.25倍。</p>`,25)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};